#include <stdio.h>
int main()
{
    long long c[10] = { 6, 2, 5, 5, 4, 5, 6, 3, 7, 6 };
    long long sum = 0;
    long long a, b, i;
    scanf( "%I64d %I64d", &a, &b );
    for( i = a; i <= b; ++i )
    {
        int j;
        j = i;
        if( j / 10 != 0 )
        while( j != 0  )
        {
            sum = sum + c[j % 10];
            j = j / 10;
        }
        else sum = sum + c[i];
    }
    printf("%d", sum);
}

