use std::io::stdin;
fn main() {
    let (a, b) = parse();
    let mut values = 0;
    for i in a..b + 1 {
        for c in i.to_string().chars() {
            values += calculate_segment(c)
        }
    }
    println!("{}", values)
}
fn parse() -> (usize, usize) {
    let mut text = String::new();
    stdin().read_line(&mut text).unwrap();
    let text: Vec<usize> = text
        .trim()
        .split_whitespace()
        .map(|e| e.parse().unwrap())
        .collect();
    (text[0], text[1])
}
fn calculate_segment(ch: char) -> usize {
    match ch {
        '0' | '6' | '9' => 6,
        '1' => 2,
        '2' | '3' | '5' => 5,
        '4' => 4,
        '7' => 3,
        '8' => 7,
        _ => 0,
    }
}
